dtsPropsFor.TypeIcon:
/** Element type: source | topic | extract | card | task | concept | media_fragment | synthesis_note. */
type: string;
/** Larger 17px variant (default 14px). */
lg?: boolean;

dtsPropsFor.ConceptTag:
/** Concept name. */
name: string;
/** When provided, the pill becomes a clickable button (filter / navigate). */
onClick?: () => void;

dtsPropsFor.SchedulerChip:
/** Scheduler signals — the load-bearing FSRS-vs-attention split. */
scheduler: {
  kind: "fsrs" | "attention";
  retrievability: number | null;
  stability: number | null;
  difficulty: number | null;
  reps: number | null;
  lapses: number | null;
  fsrsState: string | null;
  stage: string;
  postponed: number;
  lastProcessedAt: string | null;
};

dtsPropsFor.FsrsStats:
/** Scheduler signals — the load-bearing FSRS-vs-attention split. */
scheduler: {
  kind: "fsrs" | "attention";
  retrievability: number | null;
  stability: number | null;
  difficulty: number | null;
  reps: number | null;
  lapses: number | null;
  fsrsState: string | null;
  stage: string;
  postponed: number;
  lastProcessedAt: string | null;
};

dtsPropsFor.MetaRow:
/** Row key / label. */
k: string;
/** Row value. */
children?: React.ReactNode;

dtsPropsFor.Btn:
/** Visual variant (default neutral). */
variant?: "primary" | "ghost" | "soft" | "danger";
/** Size (default medium). */
size?: "sm" | "lg";
/** Leading icon name (see Icon). */
icon?: string;
/** Trailing icon name. */
iconRight?: string;
/** Full-width. */
block?: boolean;
children?: React.ReactNode;
onClick?: React.MouseEventHandler<HTMLButtonElement>;
disabled?: boolean;
type?: "button" | "submit" | "reset";
className?: string;

dtsPropsFor.Segmented:
/** Toggle options. */
options: ReadonlyArray<{ value: string; label: string; icon?: string }>;
/** The selected value. */
value: string;
/** Called with the newly-selected value. */
onChange: (value: string) => void;

dtsPropsFor.SuggestionChip:
/** Suggested priority band. */
band: "A" | "B" | "C" | "D";
/** When provided, renders as an accept button. */
onAccept?: () => void;
/** Disabled/busy state. */
busy?: boolean;
/** Compact label variant. */
compact?: boolean;

dtsPropsFor.LibrarySearchField:
/** The externally-driven query (the route q). Resets the field when it changes. */
syncQuery: string;
/** Monotonic token that forces an external sync even when syncQuery is unchanged. */
syncToken: number;
/** Emitted at most every 150ms with the latest raw text. */
onDebouncedChange: (value: string) => void;

dtsPropsFor.Icon:
/** Design-kit icon name (see design/icon-map.md, e.g. "source", "card", "brain"). */
name: string;
/** Pixel size (default 16). */
size?: number;
/** Stroke width (default 1.75 — the kit's thin weight). */
strokeWidth?: number;
className?: string;
color?: string;

dtsPropsFor.RefBlock:
/** The resolved source reference, or null (the calm orphan placeholder). */
ref: {
  sourceElementId: string | null;
  sourceTitle: string | null;
  url: string | null;
  author: string | null;
  publishedAt: string | null;
  locationLabel: string | null;
  snippet: string | null;
  sourceType: string | null;
  reliabilityTier: "primary" | "secondary" | "tertiary" | null;
  confidence: "high" | "medium" | "low" | null;
  reliabilityNotes: string | null;
} | null;
/** Jump-to-source affordance (shown when provided and the source resolves). */
onOpenSource?: () => void;
/** Render the verbatim source snippet (default true). */
showSnippet?: boolean;
/** Suppress the snippet when it duplicates nearby body text. */
dedupeSnippetAgainst?: string | null;
testId?: string;
style?: React.CSSProperties;

dtsPropsFor.ExternalUrlLink:
/** The URL to render (validated http/https; non-URLs render as plain text). */
url: string;
testId?: string;
className?: string;
/** Optional leading icon name. */
icon?: string | null;
iconSize?: number;

dtsPropsFor.LineageTree:
/** Flattened, depth-tagged lineage nodes (source → extract → … → card). */
nodes: ReadonlyArray<{
  id: string;
  type: string;
  title: string;
  stage: string;
  /** Indentation depth from the lineage root (root = 0). */
  depth: number;
  /** Short trailing label (stage / card type / "source"). */
  meta: string;
  /** True for the focused element. */
  active: boolean;
  /** True for a soft-deleted tombstone node. */
  deleted: boolean;
}>;
/** Called with the picked node (caller re-selects + navigates). */
onPick: (node: { id: string; type: string; title: string }) => void;
/** Restore a soft-deleted tombstone; omit to hide the inline Restore control. */
onRestore?: (node: { id: string }) => void;
/** Id of the tombstone whose restore is in flight. */
restoringId?: string | null;
/** Right-click report for an in-app context menu. */
onNodeContextMenu?: (node: { id: string }, position: { x: number; y: number }) => void;

dtsPropsFor.ExpiryBanner:
/** Derived expiry state (computed main-side; this only renders it). */
expiry: {
  status: "expired" | "due_for_review" | string;
  validUntil: string | null;
  reviewBy: string | null;
  jurisdiction: string | null;
  softwareVersion: string | null;
};
/** When supplied, renders a "Create verify task" button. */
onCreateTask?: () => void | Promise<void>;

dtsPropsFor.AutoPostponeReceiptLine:
/** The auto-postpone receipt, or null (renders nothing). */
receipt: {
  batchId: string;
  localDay: string;
  status: "applied" | "undone" | string;
  postponed: number;
  postponedMinutes: number;
  remainingMinutesAfter: number;
  priorityBands: readonly string[];
} | null;
/** Undo handler keyed by batchId. */
onUndo: (batchId: string) => Promise<{ undone: boolean; reason?: string }>;

dtsPropsFor.ExtractAgingReceiptLine:
/** The extract-aging receipt, or null (renders nothing). */
receipt: {
  batchId: string;
  localDay: string;
  status: "applied" | "undone" | string;
  policy: "suggest" | "automatic";
  demoted: number;
  remainingCandidateCount: number;
  thresholds: { returnThreshold: number; ageDays: number };
} | null;
/** Undo handler keyed by batchId. */
onUndo: (batchId: string) => Promise<{ undo: { undone: boolean } }>;
